external_knowledge:
- "Breached the threshold of excellence" is a metaphorical expression indicating that the accuracy metrics (precision or recall) are above a high standard;
- "Shining brighter than the mark of 90" means that the accuracy values exceed 90%;
- The 'land cover types' refer to various classifications of land use such as Asphalt, Meadows, etc.

sql:
SELECT type_name, description
FROM land_cover_types
WHERE is_permanent = 1;

SELECT metric_type, confidence_interval
FROM accuracy_metrics
WHERE accuracy_value > 90;

SELECT type_name, LENGTH(type_name) AS name_length
FROM land_cover_types
ORDER BY type_id;

SELECT result_id, type_id 
FROM classification_results 
WHERE accuracy > 95.0;

external_knowledge:
- 'urban navigators' is a metaphor for 'urban planners';
- 'steering the map of change' is a metaphor for 'conducting land cover classification';
- 'recent past month' refers to the last 30 days.

sql:
SELECT l.type_name, c.algorithm_used, c.classification_date
FROM classification_results c
INNER JOIN land_cover_types l ON c.type_id = l.type_id;

SELECT type_name 
FROM land_cover_types 
WHERE type_id = 0;

SELECT *
FROM land_cover_types
WHERE type_id > 0;

SELECT type_name, description, color_code
FROM land_cover_types
WHERE last_updated = (SELECT MIN(last_updated) FROM land_cover_types);

SELECT classification_date, accuracy 
FROM classification_results 
ORDER BY accuracy DESC;

SELECT land_cover_types.type_name, classification_results.accuracy
FROM land_cover_types
INNER JOIN classification_results ON land_cover_types.type_id = classification_results.type_id;

SELECT lc.type_name, am.accuracy_value
FROM land_cover_types AS lc
INNER JOIN accuracy_metrics AS am ON lc.type_id = am.type_id;

SELECT AVG(accuracy_value) 
FROM accuracy_metrics 
WHERE result_id = 1;

SELECT cr.confidence_score
FROM classification_results cr
ORDER BY cr.confidence_score DESC;

SELECT COUNT(DISTINCT cr.type_id) AS total_unique_types
FROM classification_results cr
WHERE cr.algorithm_used = 'RandomForest';
